// // This module implements an 8-bit synchronous down counter with a negative edge triggered clock, an active high asynchronous reset, a disable signal, and a unload signal. The counter should unload a given value when unload is high, and decrement by 1 on every negative clock edge when disable is high and reset is asserted.
module up_counter (
    input clk,
    input reset_n,
    input en,
    input load,
    input [7:0] load_val,
    output reg [7:0] q);

always @(posedge clk or negedge reset_n) begin
    if (!reset_n)
        q <= 8'b00000000;
    else if (load)
        q <= load_val;
    else if (en)
        q <= q + 1;
end

endmodule
